mapper.select:
SELECT id, name, category_id, price, unit, stock, image_url, description, bar_code, discount, is_hot, tags, status, create_time, update_time FROM product WHERE 1=1
AND (name LIKE CONCAT('%', #{keyword}, '%') OR description LIKE CONCAT('%', #{keyword}, '%') OR bar_code = #{keyword})
AND category_id = #{categoryId}
AND status = #{status}
ORDER BY create_time DESC LIMIT #{offset}, #{size}

SELECT COUNT(*) FROM product WHERE 1=1
AND (name LIKE CONCAT('%', #{keyword}, '%') OR description LIKE CONCAT('%', #{keyword}, '%') OR bar_code = #{keyword})
AND category_id = #{categoryId}
AND status = #{status}

mapper.update:
UPDATE product
name = #{name}, category_id = #{categoryId}, price = #{price}, unit = #{unit}, stock = #{stock}, image_url = #{imageUrl}, description = #{description}, bar_code = #{barCode}, discount = #{discount}, is_hot = #{isHot}, tags = #{tags}, status = #{status}, update_time = NOW()
WHERE id = #{id}

UPDATE product
SET status = #{status}, update_time = NOW()
WHERE id = #{id}

UPDATE product
SET discount = #{discount}, update_time = NOW()
WHERE id = #{id}

UPDATE product
SET stock = stock - #{quantity}
WHERE id = #{id} AND stock >= #{quantity}
